description:
Define request/response types in wtf-cli/src/client.rs:

// Request types (Data)
StartWorkflowRequest { workflow_name: String, input: serde_json::Value }
SignalRequest { signal_name: String, payload: serde_json::Value }

// Response types (Data)
StartWorkflowResponse { invocation_id: String, workflow_name: String, status: String, started_at: String }
WorkflowStatus { invocation_id: String, workflow_name: String, status: String, current_step: u32, started_at: String, updated_at: String }
WorkflowInfo { invocation_id: String, workflow_name: String, status: String, started_at: String }
JournalEntry { seq: u32, entry_type: String, name: Option<String>, input: Option<serde_json::Value>, output: Option<serde_json::Value>, timestamp: Option<String>, duration_ms: Option<u64>, fire_at: Option<String>, status: Option<String> }
JournalResponse { invocation_id: String, entries: Vec<JournalEntry> }
SignalResponse { acknowledged: bool }
ApiErrorResponse { error: String, message: String, retry_after_seconds: Option<u64> }

// ListWorkflowsResponse
ListWorkflowsResponse { workflows: Vec<WorkflowInfo> }

